import React from 'react';

const About = () => {
  return (
    <section id="about" className="about-section">
      <div className="about-container">
        <div className="about-content">
          <h2 className="section-title">About This Journey</h2>
          <p>This blog documents a transformative 16-week journey of intentional growth and learning. Each week represents a chapter in a larger story of personal and professional development.</p>
          <p>The goal was simple: commit to consistent progress, document the experience, and create a record that could inspire others to embark on their own journeys of transformation.</p>
          <p>Through challenges and victories, setbacks and breakthroughs, these weekly entries capture the authentic experience of pursuing meaningful change.</p>
        </div>
      </div>
    </section>
  );
};

export default About;
